import "./Recipes.css";
import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate, Link } from "react-router-dom";
import UserNavbar from "./UserNavbar";

export default function MyRecipe() {
  const [recipes, setRecipes] = useState([]);
  const navigate = useNavigate();

  // ================= LOAD MY RECIPES =================
  useEffect(() => {
    const token = localStorage.getItem("token");
    const userId = localStorage.getItem("user_id");

    if (!token || !userId) {
      alert("Please login first ❌");
      navigate("/login");
      return;
    }

    axios
      .get("http://127.0.0.1:8000/api/recipes/", {
        headers: {
          Authorization: `Token ${token}`,
        },
      })
      .then((res) => {
        const myRecipes = res.data
          .filter((recipe) => recipe.created_by === Number(userId))
          .map((recipe) => ({
            ...recipe,

            // FIX IMAGE
            image: recipe.image
              ? `http://127.0.0.1:8000${recipe.image}`
              : "/default-food.jpg",

            // FIX UI EXPECTATION
            author: "You",
            views: recipe.view_count,
          }));

        setRecipes(myRecipes);
      })
      .catch((err) => {
        console.error("MyRecipe error:", err);
        alert("Failed to load your recipes ❌");
      });
  }, [navigate]);

  // ================= DELETE RECIPE =================
  const deleteRecipe = async (id) => {
    const token = localStorage.getItem("token");

    if (!window.confirm("Are you sure you want to delete this recipe?")) return;

    try {
      await axios.delete(
        `http://127.0.0.1:8000/api/recipes/delete/${id}/`,
        {
          headers: {
            Authorization: `Token ${token}`,
          },
        }
      );

      alert("Recipe deleted successfully ✅");
      setRecipes(recipes.filter((r) => r.id !== id));
    } catch (err) {
      console.error(err);
      alert("Delete failed ❌");
    }
  };

  // ================= UI =================
  return (
    <>
      <UserNavbar />

      <div className="recipes-page">
        <h2>My Recipes</h2>

        <div className="recipes-grid">
          {recipes.length === 0 && <p>No recipes added yet</p>}

          {recipes.map((recipe) => (
            <div className="recipe-card" key={recipe.id}>
              <img src={recipe.image} alt={recipe.title} />

              <div className="recipe-info">
                <h3>{recipe.title}</h3>
                <p>👤 {recipe.author}</p>
                <p>👁 {recipe.views} views</p>

                <Link
                  to={`/recipedetails/${recipe.id}`}
                  className="view-btn"
                >
                  View Recipe
                </Link>

                <div style={{ marginTop: "10px" }}>
                  <button
                    onClick={() => navigate(`/editrecipe/${recipe.id}`)}
                  >
                    Edit
                  </button>

                  <button
                    onClick={() => deleteRecipe(recipe.id)}
                    style={{ marginLeft: "10px" }}
                  >
                    Delete
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </>
  );
}
